        Console.WriteLine($"  Method: {m.Name} - {m}");
        foreach (var g in m.GetGenericArguments()) {
            Console.WriteLine($"    Generic: {g.Name}");
            foreach (var c in g.GetGenericParameterConstraints())
                Console.WriteLine($"      Constraint: {c.FullName}");
            Console.WriteLine($"      Attributes: {g.GenericParameterAttributes}");
        }
    }
}
// Also check Xunit namespace
var type2 = asm.GetType("Xunit.ITestCaseOrderer");
if (type2 != null) {
    Console.WriteLine($"Found: {type2.FullName}");
}
foreach (var t in asm.GetExportedTypes().Where(t => t.Name.Contains("TestCaseOrderer"))) {
    Console.WriteLine($"Type: {t.FullName}");
}
EOF
